    public static class ReviewSanitizer
    {
        private static readonly HashSet<string> AllowedTags = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "b", "strong", "i", "em", "br"
        };

        public static string SanitizeBasicFormatting(string input)
        {
            if (string.IsNullOrWhiteSpace(input)) return string.Empty;

            var encoded = HttpUtility.HtmlEncode(input);

            encoded = encoded.Replace("\r\n", "\n").Replace("\r", "\n").Replace("\n", "<br />");

            var decoded = HttpUtility.HtmlDecode(encoded);

            return StripDisallowedTags(decoded);
        }

        private static string StripDisallowedTags(string html)
        {
            if (string.IsNullOrEmpty(html)) return string.Empty;

            var sb = new StringBuilder(html.Length);
            int i = 0;

            while (i < html.Length)
            {
                int lt = html.IndexOf('<', i);
                if (lt < 0)
                {
                    sb.Append(html, i, html.Length - i);
                    break;
                }

                if (lt > i) sb.Append(html, i, lt - i);

                int gt = html.IndexOf('>', lt + 1);
                if (gt < 0)
                {
                    sb.Append(HttpUtility.HtmlEncode(html.Substring(lt)));
                    break;
                }

                var tagContent = html.Substring(lt + 1, gt - lt - 1).Trim();

                bool isEnd = tagContent.StartsWith("/", StringComparison.Ordinal);
                if (isEnd) tagContent = tagContent.Substring(1).TrimStart();

                bool selfClosing = tagContent.EndsWith("/", StringComparison.Ordinal);
                if (selfClosing) tagContent = tagContent.Substring(0, tagContent.Length - 1).TrimEnd();

                string tagName = ExtractTagName(tagContent);
                if (tagName != null && AllowedTags.Contains(tagName))
                {
                    if (tagName.Equals("br", StringComparison.OrdinalIgnoreCase))
                    {
                        sb.Append("<br />");
                    }
                    else
                    {
                        sb.Append('<');
                        if (isEnd) sb.Append('/');
                        sb.Append(tagName.ToLowerInvariant());
                        sb.Append('>');
                    }
                }
                else
                {
                    sb.Append(HttpUtility.HtmlEncode(html.Substring(lt, gt - lt + 1)));
                }

                i = gt + 1;
            }

            return sb.ToString();
        }

        private static string ExtractTagName(string tagContent)
        {
            if (string.IsNullOrWhiteSpace(tagContent)) return null;

            int spaceIdx = tagContent.IndexOfAny(new[] { ' ', '\t', '\r', '\n' });
            string name = spaceIdx >= 0 ? tagContent.Substring(0, spaceIdx) : tagContent;

            if (name.Length == 0) return null;

            for (int i = 0; i < name.Length; i++)
            {
                char c = name[i];
                if (!(char.IsLetterOrDigit(c))) return null;
            }

            return name;
        }
