/* Views/Product/Details.cshtml */
@model MyStore.Web.Controllers.ProductDetailsViewModel
@{
    ViewBag.Title = Model.ProductName;
}

<h1>@Html.Encode(Model.ProductName)</h1>

@if (!string.IsNullOrWhiteSpace(Model.ProductDescription))
{
    <p>@Html.Encode(Model.ProductDescription)</p>
}

<h2>Reviews</h2>

@if (Model.Reviews == null || !Model.Reviews.Any())
{
    <p>No reviews yet.</p>
}
else
{
    <ul class="reviews">
        @foreach (var r in Model.Reviews)
        {
            <li class="review">
                <div class="review-meta">
                    <strong>@Html.Encode(r.AuthorName)</strong>
                    <span> - @r.CreatedUtc.ToLocalTime().ToString("yyyy-MM-dd")</span>
                    <span> - Rating: @r.Rating/5</span>
                </div>
                <div class="review-body">
                    @Html.Raw(r.SanitizedHtml)
                </div>
            </li>
        }
    </ul>
}